final:
module RefModule (
    input wire clk,
    input wire rstn,
    input wire load,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
    if (~rstn)
        data_out <= 8'b00000000;
    else if (load)
        data_out <= data_in;
    else
        data_out <= {1'b0, data_out[7:1]};
end

endmodule
